#include <stdio.h>
#include <string.h>
#include "esp_http_client.h"
#include "nvs_flash.h"

#define NVS_NAMESPACE "firmware_update"
#define FIRMWARE_KEY "binary"

static esp_err_t http_download(const char *url, const char *filename) {
    esp_http_client_config_t config = {
        .url = url,
        .method = HTTP_METHOD_GET,
        .dest_dir = "/spiffs",
        .dest_filename = filename
    };

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (client == NULL) {
        return ESP_FAIL;
    }

    esp_err_t err = esp_http_client_perform(client);
    esp_http_client_cleanup(client);

    return err;
}

static esp_err_t save_firmware_to_flash(const char *filename) {
    FILE *file = fopen(filename, "rb");
    if (file == NULL) {
        return ESP_FAIL;
    }

    nvs_handle_t handle;
    esp_err_t ret = nvs_open(NVS_NAMESPACE, NVS_READWRITE, &handle);
    if (ret != ESP_OK) {
        fclose(file);
        return ret;
    }

    size_t bytes_read;
    uint8_t buffer[1024];
    while ((bytes_read = fread(buffer, 1, sizeof(buffer), file)) > 0) {
        ret = nvs_set_blob(handle, FIRMWARE_KEY, buffer, bytes_read);
        if (ret != ESP_OK) {
            break;
        }
    }

    fclose(file);
    nvs_close(handle);

    return ret;
}

void update_firmware(const char *url) {
    const char *filename = "firmware.bin";
    esp_err_t err = http_download(url, filename);
    if (err != ESP_OK) {
        printf("Failed to download firmware: %s\n", esp_err_to_name(err));
        return;
    }

    err = save_firmware_to_flash(filename);
    if (err != ESP_OK) {
        printf("Failed to save firmware to flash: %s\n", esp_err_to_name(err));
        return;
    }

    // Reboot the device
    system_restart();
}